SELECT type, record_size, records_total, records_used
FROM V$CONTROLFILE_RECORD_SECTION
ORDER BY type;

SELECT group#, status, type, member
FROM V$LOGFILE
ORDER BY group#, member;

-- 수동 로그 스위치
ALTER SYSTEM SWITCH LOGFILE;

-- 수동 체크포인트 (ACTIVE 그룹을 INACTIVE로 전환하기 위해)
ALTER SYSTEM CHECKPOINT;

SHOW PARAMETER undo;

-- 또는 상세 조회
SELECT name, value
FROM V$PARAMETER
WHERE name LIKE 'undo%'
ORDER BY name;

SELECT tablespace_name, retention
FROM DBA_TABLESPACES
WHERE contents = 'UNDO';

-- CDB의 LOCAL_UNDO_ENABLED 설정 확인
SELECT property_name, property_value
FROM database_properties
WHERE property_name = 'LOCAL_UNDO_ENABLED';

-- V$PARAMETER에서도 확인 가능
SHOW PARAMETER local_undo_enabled;

-- Local UNDO 모드 활성화 (CDB를 UPGRADE 모드로 열어야 함)
SHUTDOWN IMMEDIATE;
STARTUP UPGRADE;
ALTER DATABASE LOCAL UNDO ON;
SHUTDOWN IMMEDIATE;
STARTUP;

-- Local UNDO 모드 비활성화 (Shared UNDO로 전환)
-- SHUTDOWN IMMEDIATE;
-- STARTUP UPGRADE;
